50	
51	const PROCESSING_FEE = 5;
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
55	const HIGH_ENCHANTMENT_MINIMUM = 5;
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const LOYALTY_MINIMUM_YEARS = 2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	
60	const BASE_PREMIUMS: Record<string, number> = {
61	  sword: 100,
62	  amulet: 60,
63	  staff: 80,
64	  potion: 40,
65	  rune: 25,
66	  moonstone: 25,
67	};
68	
69	const COMPONENT_BLOCK_SIZE = 3;
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	
72	const countByType = (items: Item[]): Map<string, number> => {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
76	  }
77	  return counts;
78	};
79	
80	const groupBasePremium = ([type, count]: [string, number]): number =>
81	  count === COMPONENT_BLOCK_SIZE
82	    ? COMPONENT_BLOCK_PREMIUM
83	    : count * BASE_PREMIUMS[type];
84	
85	const sumBy = <T>(values: T[], amount: (value: T) => number): number =>
86	  values.reduce((total, value) => total + amount(value), 0);
87	
88	const computeBasePremium = (items: Item[]): number =>
89	  sumBy([...countByType(items)], groupBasePremium);
90	
91	const itemCurseSurcharge = (item: Item): number =>
92	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
93	
94	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
95	
96	const itemHighEnchantmentSurcharge = (item: Item): number =>
97	  enchantmentOf(item) >= HIGH_ENCHANTMENT_MINIMUM
98	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
99	    : 0;
100	
101	const quotePremium = (
102	  customer: Customer,
103	  items: Item[],
104	  isFollowUp: boolean,
105	): number => {
106	  const basePremium = computeBasePremium(items);
107	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
108	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
109	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
110	  const loyaltyDiscount =
111	    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
112	      ? basePremium * LOYALTY_DISCOUNT_RATE
113	      : 0;
114	  const followUpDiscount = isFollowUp
115	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
116	    : 0;
117	  const unroundedPremium =
118	    basePremium +
119	    curseSurcharge +
120	    highEnchantmentSurcharge +
121	    firstInsuranceSurcharge -
122	    loyaltyDiscount -
123	    followUpDiscount +
124	    PROCESSING_FEE;
125	  return Math.ceil(unroundedPremium);
126	};
127	
128	const DEDUCTIBLE = 100;
129	const PAYOUT_CAP_MULTIPLIER = 2;
130	const HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT = 8;
131	const HALF_REIMBURSEMENT_RATE = 0.5;
132	
133	const INSURANCE_VALUES: Record<string, number> = {
134	  sword: 1000,
135	  amulet: 600,
136	  rune: 250,
137	};
138	
139	const insuranceValueOf = (item: Item): number => INSURANCE_VALUES[item.type];
140	
141	const reimbursementFor = (insuredItem: Item, damage: Damage): number =>
142	  enchantmentOf(insuredItem) >= HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT
143	    ? damage.amount * HALF_REIMBURSEMENT_RATE
144	    : damage.amount;
145	
146	const findInsuredItem = (insuredItems: Item[], damage: Damage): Item =>
147	  insuredItems.find((item) => item.type === damage.itemType) as Item;
148	
149	const damagePayout = (insuredItems: Item[], damage: Damage): number =>
150	  reimbursementFor(findInsuredItem(insuredItems, damage), damage) - DEDUCTIBLE;
151	
152	const settleClaim = (
153	  insuredItems: Item[],
154	  damages: Damage[],
155	  remainingCap: number,
156	): ClaimResult => {
157	  const uncappedPayout = sumBy(damages, (damage) =>
158	    damagePayout(insuredItems, damage),
159	  );
160	  const unroundedPayout = Math.min(uncappedPayout, remainingCap);
161	  const payout = Math.floor(unroundedPayout);
162	  return { payout, remainingCap: remainingCap - payout };
163	};
164	
165	const policyOf = (scenario: Scenario, claim: ClaimStep): QuoteStep =>
166	  scenario.steps[claim.policy] as QuoteStep;
167	
168	const initialCapOf = (policy: QuoteStep): number =>
169	  PAYOUT_CAP_MULTIPLIER * sumBy(policy.items, insuranceValueOf);
170	
171	export const processScenario = (scenario: Scenario): { results: Result[] } => {
172	  const remainingCaps = new Map<number, number>();
173	  return {
174	    results: scenario.steps.map((step, index) => {
175	      if (step.op === "quote") {
176	        return { premium: quotePremium(scenario.customer, step.items, index > 0) };
177	      }
178	      const policy = policyOf(scenario, step);
179	      const remainingCap =
180	        remainingCaps.get(step.policy) ?? initialCapOf(policy);
181	      const result = settleClaim(
182	        policy.items,
183	        step.incident.damages,
184	        remainingCap,
185	      );
186	      remainingCaps.set(step.policy, result.remainingCap);
187	      return result;
188	    }),
189	  };
190	};
